{
  "domain_analysis": {
    "business_context": "Order cancellation is a critical lifecycle event in logistics and courier operations. Once an order is placed, it moves through a series of fulfillment stages — each stage narrows the cancellation window and increases the cost of reversal. A cancellation policy must encode the physical realities of package handling: once a package is on a truck and in transit, 'cancellation' becomes 'recall' or 'return' — fundamentally different operations with different costs, actors, and SLAs.",
    "bounded_context": "Order Management / Order Lifecycle",
    "ubiquitous_language": [
      { "term": "Order", "definition": "A customer's request to have a package picked up from an origin and delivered to a destination, with associated service level and pricing." },
      { "term": "Order Status", "definition": "The current lifecycle stage of an order (e.g., Placed, Confirmed, Assigned, Picked Up, In Transit, Out for Delivery, Delivered, Cancelled)." },
      { "term": "Cancellation", "definition": "A customer-initiated request to void an order BEFORE the package has been physically picked up by a courier. After pickup, this is no longer a cancellation — it is a recall or return." },
      { "term": "Cancellation Window", "definition": "The set of order statuses during which cancellation is permitted. Closes once physical fulfillment begins (i.e., courier has possession of the package)." },
      { "term": "Cancellation Fee", "definition": "A charge that may apply when cancellation occurs after certain work has already been performed (e.g., courier has been dispatched but not yet picked up)." },
      { "term": "Refund", "definition": "The return of payment to the customer following a successful cancellation, minus any applicable cancellation fee." },
      { "term": "Recall", "definition": "A request to retrieve a package that is already in the courier's possession or in transit. This is NOT a cancellation — it is a separate, costlier operation." },
      { "term": "Initiator", "definition": "The actor requesting the cancellation. In this context: the customer who placed the order." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "An order may only be cancelled when its status is within the cancellation window: Placed, Confirmed, or Assigned (courier dispatched but package not yet picked up).",
      "invariant": true,
      "invariant_justification": "Once a courier has physical possession of the package, the system state must reflect physical reality. You cannot 'cancel' something that is physically in motion — that is a different operation (recall/return). Allowing cancellation post-pickup corrupts the audit trail and creates orphaned packages with no tracking.",
      "testable_assertion": "Given an order with status in {PickedUp, InTransit, OutForDelivery, Delivered}, when a cancellation request is submitted, then the system MUST reject it with an appropriate error indicating the order is no longer cancellable."
    },
    {
      "id": "BR-2",
      "rule": "Only the customer who placed the order (the order owner) may initiate a cancellation. Support agents may cancel on behalf of a customer through a separate internal flow with audit logging.",
      "invariant": true,
      "invariant_justification": "Allowing arbitrary actors to cancel orders violates data integrity and creates fraud and impersonation vectors. Order ownership is a core security invariant.",
      "testable_assertion": "Given user A's order, when user B (not an authorized support agent) attempts to cancel it, then the system MUST reject the request with a 403/unauthorized error."
    },
    {
      "id": "BR-3",
      "rule": "A cancelled order is a terminal state. A cancelled order cannot be un-cancelled, re-opened, or transitioned to any other status.",
      "invariant": true,
      "invariant_justification": "Terminal states are a state-machine integrity constraint. If cancelled orders could be reactivated, it would break billing reconciliation, courier assignment logic, and capacity planning. The customer must place a new order.",
      "testable_assertion": "Given a cancelled order, when any status transition is attempted, then the system MUST reject it and the order MUST remain in Cancelled status."
    },
    {
      "id": "BR-4",
      "rule": "When an order is cancelled, a refund MUST be initiated for any pre-collected payment, minus any applicable cancellation fee.",
      "invariant": true,
      "invariant_justification": "Collecting payment for undelivered services without refund is a legal and regulatory violation in most jurisdictions. The refund obligation is non-negotiable.",
      "testable_assertion": "Given a paid order that is successfully cancelled, then a refund record MUST be created within the same transaction or saga, and the refund amount MUST equal (amount paid - cancellation fee)."
    },
    {
      "id": "BR-5",
      "rule": "A cancellation fee MAY apply when the order status is Assigned (courier already dispatched). No fee applies when the status is Placed or Confirmed.",
      "invariant": false,
      "invariant_justification": "The fee structure and thresholds are a business policy decision that leadership can adjust. The existence and amount of cancellation fees is a commercial lever, not a system integrity constraint.",
      "testable_assertion": "Given an order in Assigned status, when cancelled, then the cancellation fee policy is applied. Given an order in Placed or Confirmed status, when cancelled, then no cancellation fee is charged."
    },
    {
      "id": "BR-6",
      "rule": "When an order in Assigned status is cancelled, the assigned courier MUST be notified and unassigned so they do not perform a wasted pickup attempt.",
      "invariant": true,
      "invariant_justification": "Failing to notify the courier results in a real-world wasted trip, fuel cost, and capacity loss. The system state must propagate to all affected actors to remain consistent with physical reality.",
      "testable_assertion": "Given an order in Assigned status with courier C assigned, when the order is cancelled, then courier C MUST receive a cancellation notification AND the courier's assignment record for that order MUST be released."
    },
    {
      "id": "BR-7",
      "rule": "Every cancellation MUST be recorded as an immutable domain event (OrderCancelled) with timestamp, initiator, reason, order status at time of cancellation, and refund details.",
      "invariant": true,
      "invariant_justification": "Auditability of cancellations is required for dispute resolution, financial reconciliation, and fraud detection. Without an immutable event record, the business cannot reconstruct what happened.",
      "testable_assertion": "Given a successful cancellation, then an OrderCancelled event MUST be persisted containing: orderId, cancelledBy, cancelledAt, reasonCode, previousStatus, refundAmount, and cancellationFee."
    },
    {
      "id": "BR-8",
      "rule": "An already-cancelled order cannot be cancelled again. The operation must be idempotent — a second cancellation request for the same order returns success but performs no additional state change.",
      "invariant": true,
      "invariant_justification": "Double-cancellation could trigger duplicate refunds, duplicate courier notifications, or duplicate events. Idempotency is a data integrity requirement.",
      "testable_assertion": "Given an order already in Cancelled status, when a cancellation request is submitted, then the system MUST return a success response and MUST NOT create a duplicate event, refund, or notification."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "An order exists in 'Placed' status with payment collected",
      "when": "The order owner requests cancellation",
      "then": "The order transitions to 'Cancelled', a full refund (no fee) is initiated, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-2",
      "given": "An order exists in 'Confirmed' status",
      "when": "The order owner requests cancellation",
      "then": "The order transitions to 'Cancelled', a full refund (no fee) is initiated, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-3",
      "given": "An order exists in 'Assigned' status with a courier dispatched",
      "when": "The order owner requests cancellation",
      "then": "The order transitions to 'Cancelled', a refund minus the cancellation fee is initiated, the courier is notified and unassigned, and an OrderCancelled event is emitted"
    },
    {
      "id": "AC-4",
      "given": "An order exists in 'PickedUp' or 'InTransit' status",
      "when": "The order owner requests cancellation",
      "then": "The request is rejected with a clear error message explaining the order is past the cancellation window, and the order status remains unchanged"
    },
    {
      "id": "AC-5",
      "given": "An order exists in 'Delivered' status",
      "when": "The order owner requests cancellation",
      "then": "The request is rejected with a clear error indicating the order has already been delivered, and the user is directed to the returns process"
    },
    {
      "id": "AC-6",
      "given": "An order exists in 'Cancelled' status (already cancelled)",
      "when": "The order owner requests cancellation again",
      "then": "The system returns a success response, no duplicate refund is issued, no duplicate event is emitted, and no courier notification is sent"
    },
    {
      "id": "AC-7",
      "given": "An order owned by User A",
      "when": "User B (not a support agent) requests cancellation of User A's order",
      "then": "The request is rejected with an authorization error, and the order remains unchanged"
    },
    {
      "id": "AC-8",
      "given": "An order exists in a cancellable status and the cancellation is processed",
      "when": "Any subsequent attempt is made to transition the order to a non-cancelled status",
      "then": "The transition is rejected, and the order remains in 'Cancelled' status"
    },
    {
      "id": "AC-9",
      "given": "An order in 'Assigned' status is cancelled",
      "when": "The courier checks their active assignments",
      "then": "The cancelled order no longer appears in the courier's assignment list"
    },
    {
      "id": "AC-10",
      "given": "A cancellation request is submitted with a reason code",
      "when": "The cancellation succeeds",
      "then": "The OrderCancelled event contains the reason code, and the reason is visible in the order history"
    }
  ],

  "edge_cases": [
    {
      "scenario": "Cancellation request arrives at the exact moment the courier marks the order as 'PickedUp' (race condition at the boundary of the cancellation window)",
      "expected_behavior": "The system must use optimistic locking or equivalent concurrency control on order status. Exactly one transition wins. If the pickup wins, the cancellation is rejected. If the cancellation wins, the courier's pickup attempt fails and the courier is informed the order was cancelled. No split-brain state is allowed."
    },
    {
      "scenario": "Payment gateway is down when the refund is initiated during cancellation",
      "expected_behavior": "The order transitions to 'Cancelled' immediately (the business decision is made), but the refund is queued for retry. The system must not block cancellation on refund success — these are separate concerns. A 'RefundPending' state must be tracked, and the refund must be retried until successful or escalated to support."
    },
    {
      "scenario": "Customer cancels an order that was placed with a promotional discount or voucher",
      "expected_behavior": "The refund restores the original payment method amount. Whether the voucher or promo code is re-credited depends on voucher policy (single-use vs. reusable). The cancellation event must record the promotional context so finance can reconcile."
    },
    {
      "scenario": "Courier notification service is unavailable when an 'Assigned' order is cancelled",
      "expected_behavior": "The cancellation proceeds (the order is cancelled and refund initiated), but courier notification is retried asynchronously. The system must track that the courier has not yet been notified and escalate if notification remains undelivered past a threshold, to prevent a wasted pickup attempt."
    },
    {
      "scenario": "Customer submits multiple rapid cancellation requests (e.g., double-clicking the cancel button)",
      "expected_behavior": "Only the first request is processed. Subsequent requests are idempotent — they return success but trigger no duplicate refunds, events, or notifications. BR-8 governs this."
    },
    {
      "scenario": "Order has no payment collected yet (e.g., cash-on-delivery model)",
      "expected_behavior": "Cancellation succeeds with no refund initiated. The OrderCancelled event records refundAmount as zero. No financial transaction is created."
    },
    {
      "scenario": "Cancellation of a multi-package or multi-leg order",
      "expected_behavior": "All packages/legs within the order are cancelled atomically. Partial cancellation of a single order is not permitted — it creates inconsistent delivery states. If partial cancellation is a business need, it must be modeled as separate orders or as a distinct 'partial cancellation' operation with its own rules."
    },
    {
      "scenario": "Support agent cancels an order on behalf of a customer",
      "expected_behavior": "The cancellation follows the same business rules (window, refund, courier notification) but the initiator is recorded as the support agent with a reference to the customer request. The audit trail must distinguish customer-initiated from agent-initiated cancellations."
    },
    {
      "scenario": "Order is in 'Assigned' status but the courier has not yet acknowledged the assignment",
      "expected_behavior": "Cancellation is permitted (still within window). The assignment is revoked. If the courier later attempts to acknowledge, they receive an error indicating the order was cancelled."
    }
  ],

  "business_impact": {
    "financial": "Cancellation directly impacts revenue (lost delivery fees), refund processing costs, and potential cancellation fee revenue. Poorly implemented cancellation (e.g., duplicate refunds, missed cancellation fees) creates direct financial leakage. Correct implementation protects revenue and reduces dispute/chargeback costs.",
    "operational": "Timely courier notification on cancellation prevents wasted pickup trips, saving fuel, time, and courier capacity. Failure to unassign couriers degrades fleet utilization. Robust idempotency prevents support ticket volume from duplicate actions.",
    "user": "Cancellation is a trust-building feature. Customers expect to cancel easily before fulfillment begins. A clear cancellation window with transparent fee policy reduces anxiety and increases order placement confidence. Rejecting cancellation post-pickup with a clear explanation (and routing to returns) prevents frustration.",
    "risk": "Primary risks: (1) Race conditions at the pickup boundary causing split-brain states, (2) Duplicate refunds from non-idempotent cancellation, (3) Regulatory risk if refunds are not processed, (4) Fraud risk if cancellation authorization is not enforced. All are mitigated by the business rules defined above.",
    "stakeholders_affected": [
      { "group": "Customers", "impact": "Gain the ability to cancel orders within a clear window; improved trust and control over their orders." },
      { "group": "Couriers", "impact": "Receive timely cancellation notifications preventing wasted trips; assignment lists stay accurate." },
      { "group": "Finance/Billing", "impact": "Must reconcile refunds and cancellation fees; need reliable event data for accounting." },
      { "group": "Customer Support", "impact": "Reduced ticket volume for manual cancellations; need tooling for agent-initiated cancellations and visibility into cancellation history." },
      { "group": "Operations/Dispatch", "impact": "Courier capacity is freed when assigned orders are cancelled; dispatch algorithms must account for cancellation-released capacity." }
    ]
  },

  "confidence": {
    "level": 42,
    "reasoning": "The spec is a single sentence with no defined order statuses, no payment model, no fee structure, no state machine, no mention of authorization rules, and no indication of whether this is a courier/logistics system or e-commerce. I have applied standard logistics domain knowledge to fill critical gaps, but nearly every business rule above is an assumption that requires stakeholder validation. The cancellation fee policy, cancellation window boundaries, multi-package behavior, and promotional refund rules are all inferred.",
    "high_confidence_areas": [
      "Cancellation must be time/status-bounded — you cannot cancel what is physically in motion",
      "Cancelled is a terminal state — no reactivation",
      "Refunds must accompany cancellation of paid orders",
      "Idempotency is required to prevent duplicate side effects",
      "Authorization: only the order owner or authorized agents can cancel"
    ],
    "low_confidence_areas": [
      "Exact order statuses and state machine (Placed, Confirmed, Assigned are assumed)",
      "Cancellation fee amounts and when they apply",
      "Payment model (prepaid vs. COD vs. invoiced)",
      "Multi-package/multi-leg order behavior",
      "Promotional/voucher refund policy",
      "Whether support-agent cancellation is in scope for this feature"
    ],
    "assumptions": [
      "This is a logistics/courier domain with physical package fulfillment",
      "Orders follow a linear state machine: Placed → Confirmed → Assigned → PickedUp → InTransit → OutForDelivery → Delivered",
      "Payment is collected at or before order placement (prepaid model)",
      "Cancellation window closes at physical pickup",
      "Cancellation fees may apply when a courier has been dispatched but not yet picked up",
      "The system emits domain events for state transitions",
      "Courier notification is a required side effect of cancelling an assigned order"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "The spec does not define which order statuses exist or which are cancellable. The cancellation window boundary (the most critical business rule in this feature) is entirely undefined.",
      "affected_stakeholders": ["Customers", "Couriers", "Operations"],
      "options": [
        "A: Cancellation allowed only before courier assignment (Placed, Confirmed)",
        "B: Cancellation allowed up to physical pickup (Placed, Confirmed, Assigned) — my assumption",
        "C: Cancellation allowed at any point before delivery, with increasing fees"
      ],
      "recommendation": "Option B — aligns with physical reality and industry standard. But PM must confirm."
    },
    {
      "type": "ambiguity",
      "description": "No cancellation fee policy is specified. Should there be a fee? When does it apply? What amount?",
      "affected_stakeholders": ["Customers", "Finance"],
      "options": [
        "A: No cancellation fee ever",
        "B: Fee only when courier is already dispatched (Assigned status)",
        "C: Tiered fees based on how close to pickup"
      ],
      "recommendation": "Option B — compensates for wasted courier dispatch without penalizing early cancellation. PM and Finance must confirm."
    },
    {
      "type": "ambiguity",
      "description": "No mention of what happens when a user tries to cancel a non-cancellable order. Should the system suggest alternatives (returns, recall)?",
      "affected_stakeholders": ["Customers", "Customer Support"],
      "options": [
        "A: Reject with generic error",
        "B: Reject with context-aware guidance (e.g., 'Your order is in transit. You can request a return instead.')"
      ],
      "recommendation": "Option B — better UX and reduces support tickets. PM must confirm."
    },
    {
      "type": "missing_context",
      "description": "No existing order state machine or domain model was provided. All order statuses and transitions are assumed based on logistics domain conventions. If the actual codebase uses different statuses or terminology, these rules must be remapped.",
      "affected_stakeholders": ["Engineering", "Product"],
      "options": [
        "Provide the existing order entity/state machine for validation",
        "Accept the proposed model as the new standard"
      ],
      "recommendation": "Provide the existing order model so acceptance criteria can be validated against actual system state."
    }
  ],

  "rejection_reasons": []
}

